def test_init(featurizer_fixture):
    assert isinstance(featurizer_fixture, Featurizer)
    assert featurizer_fixture.sample_metric == 'TbT'

def test_calculate_general_features(featurizer_fixture):
    row = featurizer_fixture.pdf.iloc[0]
    general_features = featurizer_fixture.calculate_general_features(row)
    assert isinstance(general_features, pd.Series)
    assert 'is_tbt' in general_features
    assert 'drive_left_side' in general_features

