def test_combine_features(featurizer_fixture):
    # Create mock features for testing
    general_features = pd.DataFrame({'is_tbt': [1, 0]})
    geometric_features = pd.DataFrame({'right_turns': [2, 3]})
    fcd_features_old = pd.DataFrame({'fcd_feature_old1': [0.5, 0.6]})
    fcd_features = pd.DataFrame({'fcd_feature1': [0.5, 0.6]})
    sdo_features = pd.DataFrame({'CONSTRUCTION_AHEAD_TT': [1, 0]})

    # Combine features
    combined_features = featurizer_fixture.combine_features(
        general_features,
        geometric_features,
        fcd_features_old,
        fcd_features,
        sdo_features
    )

    assert isinstance(combined_features, pd.DataFrame)
    assert list(combined_features.columns) == [
        'is_tbt',
        'right_turns',
        'fcd_feature_old1',
        'fcd_feature1',
        'CONSTRUCTION_AHEAD_TT'
    ]
